import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import API from "../../api/api";

const SubmissionView = () => {
  const { id } = useParams(); // project id
  const navigate = useNavigate();
  const [submissions, setSubmissions] = useState([]);
  const [project, setProject]         = useState(null);
  const [loading, setLoading]         = useState(true);
  const [feedback, setFeedback]       = useState({});
  const [updating, setUpdating]       = useState(null);
  const [successMsg, setSuccessMsg]   = useState("");

  useEffect(() => {
    const load = async () => {
      try {
        const [subRes, projRes] = await Promise.all([
          API.get(`/submissions/project/${id}`),
          API.get(`/projects/client`),
        ]);
        setSubmissions(subRes.data || []);
        const found = (projRes.data || []).find(p => p.id === parseInt(id));
        setProject(found || null);
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    load();
  }, [id]);

  const updateStatus = async (subId, status) => {
    setUpdating(subId);
    try {
      await API.put(`/submissions/${subId}/status`, {
        status,
        feedback: feedback[subId] || "",
      });
      const res = await API.get(`/submissions/project/${id}`);
      setSubmissions(res.data || []);
      setSuccessMsg(`Submission ${status === "approved" ? "approved ✅" : "revision requested 🔄"}`);
      setTimeout(() => setSuccessMsg(""), 3000);
    } catch (err) { alert("Failed to update status"); }
    setUpdating(null);
  };

  const statusStyle = (s) => {
    if (s === "approved")  return "bg-green-100 text-green-700 border-green-200";
    if (s === "revision")  return "bg-orange-100 text-orange-600 border-orange-200";
    return "bg-blue-100 text-blue-700 border-blue-200";
  };

  const statusIcon = (s) => {
    if (s === "approved") return "✅";
    if (s === "revision") return "🔄";
    return "📤";
  };

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-4xl mx-auto">

        {/* HEADER */}
        <div className="flex items-center gap-3 mb-6">
          <button onClick={() => navigate("/client/my-projects")}
            className="text-sm text-gray-500 hover:text-teal-600 flex items-center gap-1 transition">
            ← Back to My Projects
          </button>
        </div>

        <h1 className="text-2xl font-bold text-gray-800 mb-1">
          Work Submissions
        </h1>
        {project && (
          <p className="text-gray-500 text-sm mb-6">
            Project: <span className="font-medium text-gray-700">{project.title}</span>
          </p>
        )}

        {successMsg && (
          <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg mb-5 text-sm">
            {successMsg}
          </div>
        )}

        {submissions.length === 0 ? (
          <div className="bg-white rounded-xl p-12 text-center shadow-sm border border-gray-100">
            <div className="text-5xl mb-3">📭</div>
            <p className="text-gray-500">No submissions yet for this project.</p>
            <p className="text-gray-400 text-sm mt-1">The freelancer hasn't submitted their work yet.</p>
          </div>
        ) : (
          <div className="space-y-5">
            {submissions.map((sub) => (
              <div key={sub.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">

                {/* FREELANCER INFO */}
                <div className="flex justify-between items-start mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-teal-600 text-white rounded-full flex items-center justify-center font-bold flex-shrink-0">
                      {sub.freelancer_name?.charAt(0)?.toUpperCase()}
                    </div>
                    <div>
                      <h3 className="font-bold text-gray-800">{sub.freelancer_name}</h3>
                      <p className="text-xs text-gray-400">
                        Submitted: {new Date(sub.created_at).toLocaleDateString("en-IN", {
                          day: "2-digit", month: "short", year: "numeric"
                        })}
                      </p>
                    </div>
                  </div>
                  <span className={`px-3 py-1 rounded-full text-xs font-semibold border capitalize ${statusStyle(sub.status)}`}>
                    {statusIcon(sub.status)} {sub.status}
                  </span>
                </div>

                {/* DESCRIPTION */}
                {sub.description && (
                  <div className="bg-gray-50 rounded-lg p-4 mb-4 border border-gray-200">
                    <p className="text-sm font-medium text-gray-600 mb-1">📝 Work Description</p>
                    <p className="text-gray-700 text-sm">{sub.description}</p>
                  </div>
                )}

                {/* LINKS */}
                <div className="flex gap-4 mb-4">
                  {sub.github_link && (
                    <a href={sub.github_link} target="_blank" rel="noreferrer"
                      className="flex items-center gap-2 bg-gray-900 text-white px-4 py-2 rounded-lg text-sm hover:bg-gray-700 transition">
                      🔗 View GitHub
                    </a>
                  )}
                  {sub.live_link && (
                    <a href={sub.live_link} target="_blank" rel="noreferrer"
                      className="flex items-center gap-2 bg-teal-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-teal-700 transition">
                      🌐 Live Demo
                    </a>
                  )}
                </div>

                {/* EXISTING FEEDBACK */}
                {sub.feedback && (
                  <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-3 mb-4">
                    <p className="text-xs font-medium text-yellow-700 mb-1">Your Previous Feedback:</p>
                    <p className="text-yellow-600 text-sm">{sub.feedback}</p>
                  </div>
                )}

                {/* ACTION SECTION — only if not approved */}
                {sub.status !== "approved" && (
                  <div className="border-t border-gray-100 pt-4 mt-2">
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      💬 Feedback <span className="text-gray-400">(optional — for revision request)</span>
                    </label>
                    <textarea
                      rows={2}
                      value={feedback[sub.id] || ""}
                      onChange={e => setFeedback(prev => ({ ...prev, [sub.id]: e.target.value }))}
                      placeholder="Tell the freelancer what needs to be changed..."
                      className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none resize-none mb-3"
                    />
                    <div className="flex gap-3">
                      <button
                        onClick={() => updateStatus(sub.id, "approved")}
                        disabled={updating === sub.id}
                        className="bg-green-600 hover:bg-green-700 text-white px-5 py-2 rounded-lg text-sm font-medium transition disabled:opacity-50">
                        {updating === sub.id ? "Updating..." : "✅ Approve"}
                      </button>
                      <button
                        onClick={() => updateStatus(sub.id, "revision")}
                        disabled={updating === sub.id}
                        className="bg-orange-500 hover:bg-orange-600 text-white px-5 py-2 rounded-lg text-sm font-medium transition disabled:opacity-50">
                        🔄 Request Revision
                      </button>
                    </div>
                  </div>
                )}

                {sub.status === "approved" && (
                  <div className="border-t border-gray-100 pt-4 mt-2">
                    <div className="bg-green-50 border border-green-200 rounded-lg p-3">
                      <p className="text-green-600 text-sm font-medium">✅ You have approved this submission. Project complete!</p>
                    </div>
                  </div>
                )}

              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default SubmissionView;
